- 'Best performance' refers to the highest data transmission rate (datarate); 
- 'Most recently accessed' refers to the most recent access date; 
- 'Active' refers to the status of the configuration.

sql:
SELECT modulation_name
FROM modulations
WHERE efficiency = 2;

SELECT configuration_name
FROM configurations
ORDER BY created_date DESC, configuration_name ASC;

SELECT configuration_id
FROM configurations
ORDER BY configuration_id;
